import{_ as a,o as i,c as t,ag as l}from"./chunks/framework.DXGyWiRo.js";const o="/assets/image-0.D_xeIJk1.webp",s="/assets/image-1.-Lk1_Plr.webp",r="/assets/image-2.BrEAu0xi.webp",d="/assets/image-3.BD2kg71R.webp",P=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"tutorials/ESP-IDF-getting-started/5 手搓ESP-IDF第一个项目/index.md","filePath":"tutorials/ESP-IDF-getting-started/5 手搓ESP-IDF第一个项目/index.md","lastUpdated":null}'),p={name:"tutorials/ESP-IDF-getting-started/5 手搓ESP-IDF第一个项目/index.md"};function c(n,e,h,S,_,f){return i(),t("div",null,[...e[0]||(e[0]=[l('<div class="article-meta-card"><div class="meta-left"><div class="title-line"><span>📜 本文许可</span><a href="http://www.apache.org/licenses/LICENSE-2.0" target="_blank" class="license-badge">Apache 2.0</a></div><div class="info-line"><span>© 2026 MorkenMooooo · 作者：Mooooo</span><span>·</span><a href="https://space.bilibili.com/283444330" target="_blank">📺 Bilibili</a><a href="https://v.douyin.com/kcQ2Ofh6SiA/" target="_blank">🎵 Douyin</a><a href="/about/" target="_blank">💬 公众号</a><span>· 联系：<a href="mailto:itsntcool@qq.com">📧 邮箱</a></span></div></div><div class="meta-right"><a href="/products/" class="shop-btn"> 🚀 觉醒计划 · 配套硬件 </a></div></div><h2 id="零、如何手搓esp-idf第一个项目" tabindex="-1">零、如何手搓ESP-IDF第一个项目？ <a class="header-anchor" href="#零、如何手搓esp-idf第一个项目" aria-label="Permalink to &quot;零、如何手搓ESP-IDF第一个项目？&quot;">​</a></h2><p>流程：</p><ol><li>下载VScode</li><li>VScode下载ESP-IDF插件</li><li>使用ESP-IDF插件创建新项目</li><li>了解ESP-IDF编程新范式</li><li>手搓代码</li><li>编译、烧录到ESP32-s3</li></ol><h2 id="一、如何下载并安装vscode" tabindex="-1">一、如何下载并安装VScode？ <a class="header-anchor" href="#一、如何下载并安装vscode" aria-label="Permalink to &quot;一、如何下载并安装VScode？&quot;">​</a></h2><p>手搓第一个 ESP-IDF 项目，依旧还是老地方。打开官方开发文档链接地址：</p><p><a href="https://docs.espressif.com/projects/esp-idf/zh_CN/latest/esp32s3/get-started/index.html" target="_blank" rel="noreferrer">https://docs.espressif.com/projects/esp-idf/zh_CN/latest/esp32s3/get-started/index.html</a></p><p><img src="'+o+'" alt="构建第一个 ESP-IDF 项目的流程"></p><p>先打开 ESP-IDF 的乐鑫官网，看一下乐鑫官方示例代码是怎么说的。乐鑫官方示例里提到了手搓项目有两种方式：</p><ol><li>第一种是用命令行形式</li><li>第二种是用 IDE，也就是集成开发环境。 <ol><li>官方也提到了，IDE 有两种： <ul><li>第一种是 Eclipse</li><li>第二种是 VS Code</li></ul></li><li>后续本套课程所有的项目都将围绕着 VS Code 来管理和编写。</li><li>对于编写过代码的同学来说，应该了解过 VS Code。它是大部分程序员必备的代码编辑器，功能非常强大，由微软（Microsoft）推出。虽然也可以用 Eclipse，但我个人更倾向于使用 VS Code，所以接下来的教学都会借用 VS Code 来管理项目。</li></ol></li></ol><h2 id="二、如何在vs-code安装esp-idf插件" tabindex="-1">二、如何在VS code安装ESP-IDF插件？ <a class="header-anchor" href="#二、如何在vs-code安装esp-idf插件" aria-label="Permalink to &quot;二、如何在VS code安装ESP-IDF插件？&quot;">​</a></h2><h3 id="安装3个主要插件" tabindex="-1">安装3个主要插件： <a class="header-anchor" href="#安装3个主要插件" aria-label="Permalink to &quot;安装3个主要插件：&quot;">​</a></h3><ol><li>ESP-IDF</li><li>C/C++</li><li>C/C++ pack</li><li>中文汉化插件（自行适配）</li><li>UI主题插件（防止眼睛疲劳）</li></ol><p>因此我们现在需要做的第一件事情，就是下载安装 VS Code。</p><p>VS Code 的下载、安装非常简易方便，而且可以借由 ESP-IDF 插件来管理项目、创建项目，并对 ESP-IDF 项目进行代码编辑、编译、烧录和监视等等，这些操作都非常方便，接下来我们就开始。</p><h4 id="具体步骤如下" tabindex="-1">具体步骤如下： <a class="header-anchor" href="#具体步骤如下" aria-label="Permalink to &quot;具体步骤如下：&quot;">​</a></h4><ol><li>打开 VS Code 官网下载链接</li></ol><p><a href="https://code.visualstudio.com/" target="_blank" rel="noreferrer">https://code.visualstudio.com/</a></p><ol><li>点击 Download 下载 VS Code</li></ol><p><img src="'+s+'" alt="VS Code 官网下载界面：Windows 版本"></p><ol><li>安装 VS Code</li><li>管理 VS Code 里的插件</li></ol><p>在管理插件这一步，需要下载以下三个内容：</p><p>(a) C++ 插件</p><p>(b) ESP-IDF 插件</p><p>(c) 主题（可以保护眼睛，防止疲劳）</p><h2 id="三、怎么看vs-code的esp-idf插件底部导航栏介绍" tabindex="-1">三、怎么看VS code的ESP-IDF插件底部导航栏介绍？ <a class="header-anchor" href="#三、怎么看vs-code的esp-idf插件底部导航栏介绍" aria-label="Permalink to &quot;三、怎么看VS code的ESP-IDF插件底部导航栏介绍？&quot;">​</a></h2><h3 id="_3-1-要安装的插件" tabindex="-1">3.1 要安装的插件 <a class="header-anchor" href="#_3-1-要安装的插件" aria-label="Permalink to &quot;3.1 要安装的插件&quot;">​</a></h3><p><img src="'+r+'" alt="必须安装的extention插件"></p><h3 id="_3-2-esp-idf插件底部导航栏介绍" tabindex="-1">3.2 ESP-IDF插件底部导航栏介绍 <a class="header-anchor" href="#_3-2-esp-idf插件底部导航栏介绍" aria-label="Permalink to &quot;3.2 ESP-IDF插件底部导航栏介绍&quot;">​</a></h3><p><img src="'+d+'" alt="ESP-IDF插件底部导航栏介绍"></p>',30)])])}const u=a(p,[["render",c]]);export{P as __pageData,u as default};
